import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const Navbar = () => {

  // 🔹 Time-based greeting
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  const user = {
    name: "Priyanshu",
    isLoggedIn: true
  };

  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <div className="w-full bg-gradient-to-br from-[#141E30] to-[#243B55] px-4 md:px-6 py-4">

      {/* 🔥 MAIN NAVBAR */}
      <div className="w-full flex items-center justify-between bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl px-4 md:px-6 py-4 shadow-lg">

        {/* LEFT */}
        <div className="flex-1 min-w-0">
          <h1 className="text-sm sm:text-lg md:text-xl font-semibold text-white truncate">
            👋 {getGreeting()}, {user.isLoggedIn ? user.name : "Guest"}
          </h1>

          <p className="text-xs md:text-sm text-white/70 mt-1">
            Be efficient, be productive.
          </p>
        </div>

        {/* 🔥 DESKTOP MENU */}
        <div className="hidden md:flex items-center gap-5 text-white">

          <button className="flex items-center gap-2 hover:text-indigo-400 transition">
            Add Task
          </button>

          <button className="flex items-center gap-2 hover:text-indigo-400 transition">
            Categories
          </button>

          <button className="flex items-center gap-2 hover:text-red-400 transition">
            Purge Tasks
          </button>

          {user.isLoggedIn && (
            <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl border border-white/20">
              <img
                src="https://i.pravatar.cc/40"
                alt="profile"
                className="w-8 h-8 rounded-full"
              />
              <span className="text-sm">{user.name}</span>
            </div>
          )}

          {user.isLoggedIn ? (
            <button className="px-4 py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500">
              Logout
            </button>
          ) : (
            <button className="px-4 py-2 rounded-xl bg-gradient-to-r from-green-400 to-blue-500">
              Login
            </button>
          )}

        </div>

        {/* 🔥 MOBILE HAMBURGER (FIXED) */}
        <button
          onClick={() => setMenuOpen(true)}
          className="md:hidden text-white text-2xl ml-3"
        >
          ☰
        </button>

      </div>

      {/* 🔥 MOBILE DRAWER */}
      <AnimatePresence>
        {menuOpen && (
          <>
            {/* BACKDROP */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setMenuOpen(false)}
              className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40"
            />

            {/* DRAWER */}
            <motion.div
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ duration: 0.3 }}
              className="fixed top-0 right-0 w-[85%] max-w-sm h-full bg-[#0f172a] z-50 p-6 flex flex-col justify-between"
            >

              {/* TOP */}
              <div>

                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-white text-lg font-semibold">Menu</h2>
                  <button
                    onClick={() => setMenuOpen(false)}
                    className="text-white text-xl"
                  >
                    ✖
                  </button>
                </div>

                {/* MENU ITEMS */}
                <div className="flex flex-col gap-6 text-white text-lg">

                  <button className="flex items-center gap-3">
                    ➕ Add Task
                  </button>

                  <button className="flex items-center gap-3">
                    🔺 Categories
                  </button>

                  <button className="flex items-center gap-3 text-red-400">
                    🗑 Purge Tasks
                  </button>

                </div>

              </div>

              {/* BOTTOM */}
              <div className="space-y-4">

                {user.isLoggedIn && (
                  <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl">
                    <img
                      src="https://i.pravatar.cc/40"
                      alt="profile"
                      className="w-9 h-9 rounded-full"
                    />
                    <span className="text-white">{user.name}</span>
                  </div>
                )}

                {user.isLoggedIn ? (
                  <button className="w-full py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500 text-white">
                    Logout
                  </button>
                ) : (
                  <button className="w-full py-2 rounded-xl bg-gradient-to-r from-green-400 to-blue-500 text-white">
                    Login
                  </button>
                )}

              </div>

            </motion.div>
          </>
        )}
      </AnimatePresence>

    </div>
  );
};

export default Navbar;
